import{_ as c,C as l,o as d,c as h,a2 as r,b as o,w as e,a as i,E as s,a3 as n}from"./chunks/framework.c3r8iWL8.js";const R=JSON.parse('{"title":"Governance Model","description":"Reference template for AI-native enterprise delivery on AWS","frontmatter":{},"headers":[],"relativePath":"GOVERNANCE.md","filePath":"GOVERNANCE.md","lastUpdated":1783100276000}'),p={name:"GOVERNANCE.md"};function m(g,t,u,A,f,b){const a=l("Mermaid");return d(),h("div",null,[t[2]||(t[2]=r('<h1 id="governance-model" tabindex="-1">Governance Model <a class="header-anchor" href="#governance-model" aria-label="Permalink to &quot;Governance Model&quot;">​</a></h1><p><strong>Reference model</strong> — adapt roles, tiers, and gates to your organization. Record <strong>your</strong> choices in <strong>your</strong> project&#39;s ADRs.</p><p>Roles, decision rights, service tiers, and artifact lifecycle. SOPs in <a href="./sops/">sops/index.md</a> are <strong>playbooks to customize</strong>, not procedures executed from this repo.</p><p><strong>Compare governance approaches:</strong> <a href="./guides/human-in-the-loop-governance.html">Guide: Human-in-the-loop</a></p><hr><h2 id="design-improvements-from-initial-brainstorm" tabindex="-1">Design improvements (from initial brainstorm) <a class="header-anchor" href="#design-improvements-from-initial-brainstorm" aria-label="Permalink to &quot;Design improvements (from initial brainstorm)&quot;">​</a></h2><p>The first draft listed tools and layers broadly. This revision tightens the model in six ways:</p><table tabindex="0"><thead><tr><th>Gap in brainstorm</th><th>Improvement</th></tr></thead><tbody><tr><td>Tool list without priority</td><td><strong>Primary vs optional</strong> stack per layer (see <a href="./ARCHITECTURE.html">ARCHITECTURE.md</a>)</td></tr><tr><td>&quot;Zero manual QA&quot; overstated</td><td><strong>Automated verification standard</strong> — no manual test execution; humans still review artifacts, PRs, and staging behavior</td></tr><tr><td>Human gates listed but not owned</td><td><strong>RACI + decision rights</strong> below</td></tr><tr><td>ADR/spec flow described twice</td><td><strong>Single artifact lifecycle</strong> with machine-readable status</td></tr><tr><td>No entry criteria for coding</td><td><strong>Implementation unlock</strong> requires Approved spec + Accepted ADRs + security sign-off when applicable</td></tr><tr><td>Monitoring loop vague</td><td><strong>SLO-owned feedback</strong> with mandatory regression artifact within 48h of Sev-1/2</td></tr></tbody></table><hr><h2 id="roles" tabindex="-1">Roles <a class="header-anchor" href="#roles" aria-label="Permalink to &quot;Roles&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Role</th><th>Abbrev</th><th>Primary responsibility</th></tr></thead><tbody><tr><td>Product Owner</td><td>PO</td><td>Prioritize work; approve acceptance criteria and staging behavior</td></tr><tr><td>Architect / Tech Lead</td><td>ARCH</td><td>Approve ADRs, API contracts, cross-service design</td></tr><tr><td>Developer</td><td>DEV</td><td>Implement against approved spec; propose ADRs; review PRs</td></tr><tr><td>Security Engineer</td><td>SEC</td><td>Approve threat models; own policy exceptions</td></tr><tr><td>SRE / Platform</td><td>SRE</td><td>Deploy gates, SLOs, incident response, runbooks</td></tr><tr><td>AI Platform Owner</td><td>AIPO</td><td>Bedrock/Q/MCP config, prompt policies, agent audit</td></tr><tr><td>Data steward</td><td>DATA</td><td>Classification glossary, catalog quality, retention policy</td></tr><tr><td>Engineering Manager</td><td>EM</td><td>Escalation, capacity, exception approval (non-security)</td></tr></tbody></table><hr><h2 id="raci-by-lifecycle-phase" tabindex="-1">RACI by lifecycle phase <a class="header-anchor" href="#raci-by-lifecycle-phase" aria-label="Permalink to &quot;RACI by lifecycle phase&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Phase</th><th>PO</th><th>ARCH</th><th>DEV</th><th>SEC</th><th>SRE</th><th>AIPO</th><th>DATA</th></tr></thead><tbody><tr><td>Feature intake</td><td><strong>A</strong></td><td>C</td><td>I</td><td>C</td><td>I</td><td>—</td><td>C</td></tr><tr><td>Spec drafting (AI-assisted)</td><td>R</td><td><strong>A</strong></td><td>C</td><td>C</td><td>I</td><td>C</td><td>C</td></tr><tr><td>ADR approval</td><td>I</td><td><strong>A</strong></td><td>R</td><td>C</td><td>C</td><td>—</td><td>I</td></tr><tr><td>Implementation</td><td>I</td><td>C</td><td><strong>R/A</strong></td><td>I</td><td>I</td><td>C</td><td>I</td></tr><tr><td>PR merge</td><td>I</td><td>C</td><td><strong>R</strong> (reviewer <strong>A</strong>)</td><td>I</td><td>I</td><td>—</td><td>—</td></tr><tr><td>Staging validation</td><td><strong>A</strong></td><td>I</td><td>R</td><td>I</td><td>C</td><td>—</td><td>—</td></tr><tr><td>Production deploy (Tier 1)</td><td>I</td><td>C</td><td>R</td><td>I</td><td><strong>A</strong></td><td>—</td><td>—</td></tr><tr><td>Production deploy (Tier 2–3)</td><td>I</td><td>I</td><td>R</td><td>I</td><td><strong>A</strong> (automated)</td><td>—</td><td>—</td></tr><tr><td>Incident response</td><td>I</td><td>C</td><td>R</td><td>C</td><td><strong>A</strong></td><td>—</td><td>C</td></tr><tr><td>Post-incident artifacts</td><td>I</td><td>C</td><td><strong>R</strong></td><td>I</td><td><strong>A</strong></td><td>—</td><td>I</td></tr><tr><td>AI tool / data policy</td><td>I</td><td>C</td><td>I</td><td><strong>A</strong></td><td>I</td><td><strong>R</strong></td><td>C</td></tr><tr><td>Data classification change</td><td>C</td><td>C</td><td>I</td><td><strong>A</strong></td><td>I</td><td>C</td><td><strong>R</strong></td></tr></tbody></table><p><strong>R</strong> = Responsible · <strong>A</strong> = Accountable · <strong>C</strong> = Consulted · <strong>I</strong> = Informed</p><hr><h2 id="decision-rights" tabindex="-1">Decision rights <a class="header-anchor" href="#decision-rights" aria-label="Permalink to &quot;Decision rights&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Decision</th><th>Who decides</th><th>AI may recommend</th><th>Escalation</th></tr></thead><tbody><tr><td>Business priority</td><td>PO</td><td>Yes (impact summary)</td><td>EM</td></tr><tr><td>API contract shape</td><td>ARCH</td><td>Yes (draft OpenAPI)</td><td>Architecture review board</td></tr><tr><td>Technology / pattern choice</td><td>ARCH (via ADR)</td><td>Yes (options analysis)</td><td>ARB if cross-team</td></tr><tr><td>Merge to main</td><td>DEV reviewer + CI</td><td>AI review advisory</td><td>ARCH if ADR conflict</td></tr><tr><td>Production deploy Tier 1</td><td>SRE + ARCH</td><td>No</td><td>EM</td></tr><tr><td>Security policy exception</td><td>SEC</td><td>No</td><td>CISO delegate</td></tr><tr><td>Production data in AI prompts</td><td>SEC + AIPO</td><td>No</td><td>Always deny by default</td></tr><tr><td>SLO / alert threshold change</td><td>SRE</td><td>Yes (baseline analysis)</td><td>ARCH if customer-facing</td></tr></tbody></table><hr><h2 id="service-tiers" tabindex="-1">Service tiers <a class="header-anchor" href="#service-tiers" aria-label="Permalink to &quot;Service tiers&quot;">​</a></h2><p>Tier drives test rigor, deploy gates, and on-call expectations.</p><table tabindex="0"><thead><tr><th>Tier</th><th>Examples</th><th>Mutation floor</th><th>Prod deploy</th><th>On-call</th></tr></thead><tbody><tr><td><strong>T1</strong></td><td>Auth, payments, PII</td><td>85%</td><td>Manual approval + canary</td><td>24×7 page</td></tr><tr><td><strong>T2</strong></td><td>Core APIs, order flow</td><td>75%</td><td>Automated canary</td><td>Business hours + page</td></tr><tr><td><strong>T3</strong></td><td>Internal tools, batch</td><td>60%</td><td>Automated</td><td>Best effort</td></tr></tbody></table><p>Tier is recorded in Backstage <code>catalog-info.yaml</code> and enforced in CI via labels.</p><hr><h2 id="artifact-lifecycle" tabindex="-1">Artifact lifecycle <a class="header-anchor" href="#artifact-lifecycle" aria-label="Permalink to &quot;Artifact lifecycle&quot;">​</a></h2><p>All planning artifacts use Git-managed status. CI enforces transitions.</p>',26)),(d(),o(n,null,{default:e(()=>[s(a,{id:"mermaid-768",class:"mermaid",graph:"stateDiagram-v2%0A%20%20%20%20%5B*%5D%20--%3E%20Draft%3A%20AI%20or%20human%20creates%0A%20%20%20%20Draft%20--%3E%20InReview%3A%20Open%20PR%0A%20%20%20%20InReview%20--%3E%20Approved%3A%20Human%20gate%20passed%0A%20%20%20%20InReview%20--%3E%20Rejected%3A%20Review%20failed%0A%20%20%20%20Approved%20--%3E%20Indexed%3A%20Merge%20to%20main%0A%20%20%20%20Indexed%20--%3E%20Superseded%3A%20New%20version%20merged%0A%20%20%20%20Rejected%20--%3E%20%5B*%5D%0A%20%20%20%20Superseded%20--%3E%20%5B*%5D%0A"})]),fallback:e(()=>[...t[0]||(t[0]=[i(" Loading... ",-1)])]),_:1})),t[3]||(t[3]=r('<h3 id="spec-status-specs-openapi-yaml-→-info-x-status" tabindex="-1">Spec status (<code>specs/openapi/*.yaml</code> → <code>info.x-status</code>) <a class="header-anchor" href="#spec-status-specs-openapi-yaml-→-info-x-status" aria-label="Permalink to &quot;Spec status (`specs/openapi/*.yaml` → `info.x-status`)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th><th>Blocks implementation PR</th></tr></thead><tbody><tr><td><code>draft</code></td><td>Work in progress</td><td>Yes</td></tr><tr><td><code>in-review</code></td><td>PR open</td><td>Yes</td></tr><tr><td><code>approved</code></td><td>ARCH + PO signed off</td><td>No</td></tr><tr><td><code>deprecated</code></td><td>Replaced</td><td>Yes (use successor)</td></tr></tbody></table><h3 id="adr-status-docs-adr-md-front-matter" tabindex="-1">ADR status (<code>docs/adr/*.md</code> front matter) <a class="header-anchor" href="#adr-status-docs-adr-md-front-matter" aria-label="Permalink to &quot;ADR status (`docs/adr/*.md` front matter)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Status</th><th>Indexed for AI agents</th><th>Blocks implementation</th></tr></thead><tbody><tr><td><code>proposed</code></td><td>No</td><td>Yes (if decision required)</td></tr><tr><td><code>accepted</code></td><td>Yes</td><td>No</td></tr><tr><td><code>rejected</code></td><td>No</td><td>N/A</td></tr><tr><td><code>superseded</code></td><td>No (successor linked)</td><td>N/A</td></tr></tbody></table><h3 id="implementation-unlock-checklist" tabindex="-1">Implementation unlock checklist <a class="header-anchor" href="#implementation-unlock-checklist" aria-label="Permalink to &quot;Implementation unlock checklist&quot;">​</a></h3><p>Before a feature branch may merge implementation code:</p><ul><li>[ ] Linked spec is <code>approved</code></li><li>[ ] All referenced ADRs are <code>accepted</code> (or explicitly not required — logged in ticket)</li><li>[ ] Threat model reviewed by SEC when tier T1/T2 and external exposure</li><li>[ ] Ticket links spec, ADR IDs, and tier</li></ul><p>CI label <code>implementation-unlocked</code> is applied by workflow when checks pass.</p><hr><h2 id="escalation-paths" tabindex="-1">Escalation paths <a class="header-anchor" href="#escalation-paths" aria-label="Permalink to &quot;Escalation paths&quot;">​</a></h2>',10)),(d(),o(n,null,{default:e(()=>[s(a,{id:"mermaid-932",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20DEV%5BDeveloper%20blocked%5D%20--%3E%20TL%5BTech%20lead%20%2F%20ARCH%5D%0A%20%20%20%20TL%20--%3E%20ARB%5BArchitecture%20review%20%E2%80%94%20weekly%5D%0A%20%20%20%20SEC_BLOCK%5BSecurity%20scan%20failure%5D%20--%3E%20SEC%5BSecurity%20engineer%5D%0A%20%20%20%20SEC%20--%3E%20CISO%5BCISO%20delegate%20%E2%80%94%20exception%20only%5D%0A%20%20%20%20INC%5BSev-1%20incident%5D%20--%3E%20SRE%5BSRE%20on-call%5D%0A%20%20%20%20SRE%20--%3E%20EM%5BEM%20%2B%20ARCH%20within%201h%5D%0A%20%20%20%20AI%5BAI%20policy%20violation%5D%20--%3E%20AIPO%5BAI%20platform%20owner%5D%0A%20%20%20%20AIPO%20--%3E%20SEC%0A"})]),fallback:e(()=>[...t[1]||(t[1]=[i(" Loading... ",-1)])]),_:1})),t[4]||(t[4]=r('<hr><h2 id="metrics-health-governance-view" tabindex="-1">Metrics &amp; health (governance view) <a class="header-anchor" href="#metrics-health-governance-view" aria-label="Permalink to &quot;Metrics &amp; health (governance view)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Metric</th><th>Target</th><th>Owner</th></tr></thead><tbody><tr><td>Spec approved before first impl commit</td><td>100%</td><td>ARCH</td></tr><tr><td>ADR time-to-accept</td><td>≤ 3 business days</td><td>ARCH</td></tr><tr><td>PR cycle time (median)</td><td>≤ 1 day</td><td>EM</td></tr><tr><td>Main branch CI pass rate</td><td>≥ 95%</td><td>SRE</td></tr><tr><td>Escaped defects (no prior alert)</td><td>Down quarter-over-quarter</td><td>SRE</td></tr><tr><td>Regression test added post Sev-1/2</td><td>100% within 48h</td><td>DEV</td></tr></tbody></table><hr><h2 id="related-documents" tabindex="-1">Related documents <a class="header-anchor" href="#related-documents" aria-label="Permalink to &quot;Related documents&quot;">​</a></h2><ul><li><a href="./processes/overview.html">Process overview</a></li><li><a href="./sops/">SOP index</a></li><li><a href="./ARCHITECTURE.html">Architecture</a></li></ul>',6))])}const I=c(p,[["render",m]]);export{R as __pageData,I as default};
